// Antigravity Remote Control (ARC) Injected Dashboard script
(function() {
    console.log('[ARC] Initializing Remote Control Dashboard...');

    // SVG icons definitions matching premium monochromatic line style
    const ICONS = {
        bell: `<svg class="arc-icon" viewBox="0 0 24 24"><path d="M18 8A6 6 0 0 0 6 8c0 7-3 9-3 9h18s-3-2-3-9"></path><path d="M13.73 21a2 2 0 0 1-3.46 0"></path></svg>`,
        bellOff: `<svg class="arc-icon" viewBox="0 0 24 24"><path d="M13.73 21a2 2 0 0 1-3.46 0"></path><path d="M18.63 13A17.89 17.89 0 0 1 18 8"></path><path d="M6.26 6.26A5.86 5.86 0 0 0 6 8c0 7-3 9-3 9h14"></path><path d="M18 8a6 6 0 0 0-9.33-5"></path><line x1="1" y1="1" x2="23" y2="23"></line></svg>`,
        pause: `<svg class="arc-icon" viewBox="0 0 24 24"><rect x="6" y="4" width="4" height="16"></rect><rect x="14" y="4" width="4" height="16"></rect></svg>`,
        play: `<svg class="arc-icon" viewBox="0 0 24 24"><polygon points="5 3 19 12 5 21 5 3"></polygon></svg>`,
        power: `<svg class="arc-icon" viewBox="0 0 24 24"><path d="M18.36 6.64a9 9 0 1 1-12.73 0"></path><line x1="12" y1="2" x2="12" y2="12"></line></svg>`,
        info: `<svg class="arc-icon" viewBox="0 0 24 24"><circle cx="12" cy="12" r="10"></circle><line x1="12" y1="16" x2="12" y2="12"></line><line x1="12" y1="8" x2="12.01" y2="8"></line></svg>`
    };

    // Add Stylesheet to the page
    const styles = `
        @import url('https://fonts.googleapis.com/css2?family=Outfit:wght@300;400;500;600&display=swap');

        #arc-bar {
            position: fixed;
            top: 0;
            left: 0;
            right: 0;
            height: 52px;
            background: rgba(22, 22, 23, 0.8);
            backdrop-filter: saturate(180%) blur(20px);
            -webkit-backdrop-filter: saturate(180%) blur(20px);
            border-bottom: 1px solid rgba(255, 255, 255, 0.08);
            z-index: 999999;
            display: flex;
            align-items: center;
            justify-content: space-between;
            padding: 0 24px;
            font-family: "Google Sans", "Product Sans", "Outfit", -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif !important;
            color: #f5f5f7;
            box-shadow: 0 4px 30px rgba(0, 0, 0, 0.15);
            transition: background 0.3s ease, border-color 0.3s ease, box-shadow 0.3s ease;
        }

        #arc-bar:hover {
            background: rgba(22, 22, 23, 0.85);
            border-bottom: 1px solid rgba(255, 255, 255, 0.12);
        }

        .arc-left {
            display: flex;
            align-items: center;
            gap: 16px;
        }

        .arc-logo {
            font-family: "Google Sans", "Product Sans", "Outfit", -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif !important;
            font-weight: 300;
            font-size: 15px;
            color: #f5f5f7;
            letter-spacing: -0.01em;
            display: flex;
            align-items: center;
            text-transform: lowercase;
            -webkit-font-smoothing: antialiased;
            gap: 6px;
        }

        .arc-logo-text {
            font-family: "Google Sans", "Product Sans", "Outfit", -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif !important;
            font-weight: 500;
            font-size: 14px;
            color: #f5f5f7;
            letter-spacing: -0.01em;
            text-transform: none;
            -webkit-font-smoothing: antialiased;
        }

        .arc-logo-img {
            height: 18px;
            width: auto;
            display: inline-block;
            vertical-align: middle;
            opacity: 1;
            transition: opacity 0.2s cubic-bezier(0.25, 1, 0.5, 1);
        }

        #arc-bar:hover .arc-logo-img {
            opacity: 1;
        }

        .arc-logo-sub {
            font-family: "Google Sans", "Product Sans", "Outfit", -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif !important;
            font-weight: 500;
            color: #86868b;
            font-size: 10px;
            letter-spacing: 0.08em;
            text-transform: uppercase;
            background: rgba(255, 255, 255, 0.06);
            border: 1px solid rgba(255, 255, 255, 0.06);
            padding: 1px 5px;
            border-radius: 4px;
        }

        .arc-badge {
            font-family: "Google Sans", "Product Sans", "Outfit", -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif !important;
            display: flex;
            align-items: center;
            gap: 6px;
            background: rgba(255, 255, 255, 0.03);
            border: 1px solid rgba(255, 255, 255, 0.06);
            padding: 3px 8px;
            border-radius: 12px;
            font-size: 11px;
            font-weight: 400;
            color: #86868b;
            letter-spacing: -0.01em;
        }

        .arc-dot {
            width: 6px;
            height: 6px;
            border-radius: 50%;
            background-color: #10b981;
            opacity: 0.8;
            animation: pulse-dot 2.5s infinite ease-in-out;
        }

        @keyframes pulse-dot {
            0%, 100% { opacity: 0.45; }
            50% { opacity: 0.95; }
        }

        .arc-right {
            display: flex;
            align-items: center;
            gap: 12px;
        }

        .arc-btn {
            font-family: "Google Sans", "Product Sans", "Outfit", -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif !important;
            background: rgba(255, 255, 255, 0.03);
            border: 1px solid rgba(255, 255, 255, 0.06);
            color: #86868b;
            padding: 6px 12px;
            border-radius: 6px;
            font-size: 12px;
            font-weight: 400;
            cursor: pointer;
            transition: all 0.2s cubic-bezier(0.25, 1, 0.5, 1);
            display: flex;
            align-items: center;
            gap: 6px;
            -webkit-font-smoothing: antialiased;
        }

        .arc-btn:hover {
            background: rgba(255, 255, 255, 0.06);
            border-color: rgba(255, 255, 255, 0.12);
            color: #c5c5c9;
        }

        .arc-btn:active {
            background: rgba(255, 255, 255, 0.04);
            transform: scale(0.95);
        }

        .arc-btn-active {
            background: rgba(255, 255, 255, 0.08) !important;
            border-color: rgba(255, 255, 255, 0.24) !important;
            color: #f5f5f7 !important;
        }

        .arc-btn-active:hover {
            background: rgba(255, 255, 255, 0.12) !important;
            border-color: rgba(255, 255, 255, 0.32) !important;
            color: #ffffff !important;
        }

        .arc-btn-alert {
            background: rgba(255, 255, 255, 0.03);
            border: 1px solid rgba(255, 255, 255, 0.06);
            color: #86868b;
        }

        .arc-btn-alert:hover {
            background: rgba(239, 68, 68, 0.08);
            border-color: rgba(239, 68, 68, 0.2);
            color: #f87171;
        }

        .arc-icon {
            display: inline-block;
            width: 14px;
            height: 14px;
            stroke: currentColor;
            stroke-width: 1.5;
            fill: none;
            stroke-linecap: round;
            stroke-linejoin: round;
            vertical-align: middle;
            flex-shrink: 0;
            transition: stroke 0.2s ease;
        }

        /* Shift original app root down to make space for our gorgeous bar */
        html, body {
            height: 100% !important;
            overflow: hidden !important; /* Prevents any scrolling of the main window layout */
        }

        body {
            padding-top: 0px !important;
            box-sizing: border-box !important;
        }

        /* Custom notifications modal styling */
        #arc-toast-container {
            position: fixed;
            bottom: 24px;
            right: 24px;
            z-index: 9999999;
            display: flex;
            flex-direction: column;
            gap: 10px;
        }

        .arc-toast {
            background: rgba(22, 22, 23, 0.9);
            backdrop-filter: saturate(180%) blur(20px);
            -webkit-backdrop-filter: saturate(180%) blur(20px);
            border: 1px solid rgba(255, 255, 255, 0.08);
            color: #e8e8ed;
            padding: 10px 16px;
            border-radius: 8px;
            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.3);
            display: flex;
            align-items: center;
            gap: 10px;
            font-family: "Google Sans", "Product Sans", "Outfit", -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif !important;
            font-size: 12px;
            transform: translateY(20px);
            opacity: 0;
            animation: slide-in-toast 0.35s cubic-bezier(0.25, 1, 0.5, 1) forwards;
            max-width: 320px;
        }

        @keyframes slide-in-toast {
            to {
                transform: translateY(0);
                opacity: 1;
            }
        }

        /* Responsive Mobile Optimized Styling */
        @media (max-width: 600px) {
            #arc-bar {
                height: 38px;
                padding: 0 12px;
            }
            body {
                padding-top: 0px !important;
            }
            html {
                font-size: 112% !important; /* Scale up Tailwind rem-based elements */
            }
            .arc-logo {
                font-size: 13px;
            }
            .arc-logo-text {
                font-size: 12px;
            }
            .arc-logo-sub {
                font-size: 8px;
                padding: 0.5px 3px;
                margin-left: 4px;
            }
            .arc-badge {
                background: none !important;
                border: none !important;
                padding: 0 !important;
                gap: 0 !important;
                box-shadow: none !important;
            }
            .arc-badge-text {
                display: none !important;
            }
            .arc-right {
                gap: 8px;
            }
            .arc-btn {
                padding: 0 !important;
                width: 28px !important;
                height: 28px !important;
                border-radius: 6px !important;
                justify-content: center !important;
                align-items: center !important;
            }
            .arc-btn-text {
                display: none !important;
            }
            #arc-toast-container {
                bottom: 12px;
                right: 12px;
                left: 12px;
            }
            .arc-toast {
                max-width: 100%;
                font-size: 11px;
                padding: 8px 12px;
                border-radius: 6px;
            }
        }

        /* ── Mobile fix: Antigravity question/decision modal overflow ── */
        /* Force all message containers and cards to respect the viewport width */
        @media (max-width: 768px) {
            /* Global box model fix for all elements inside the app */
            #root *, #root *::before, #root *::after {
                box-sizing: border-box !important;
            }

            /* Prevent any element from overflowing horizontally */
            #root {
                max-width: 100vw !important;
                overflow-x: hidden !important;
            }

            /* Message bubble / card containers — Tailwind uses these patterns */
            #root [class*="rounded"][class*="border"],
            #root [class*="rounded"][class*="bg-"],
            #root [class*="card"],
            #root [class*="message"],
            #root [class*="bubble"] {
                max-width: 100% !important;
                width: auto !important;
                min-width: 0 !important;
                overflow-wrap: break-word !important;
                word-break: break-word !important;
            }

            /* Decision/question modal: question text and options list */
            /* Target the fixed-bottom panel that contains question + options */
            #root [class*="fixed"][class*="bottom"],
            #root [class*="sticky"][class*="bottom"] {
                left: 0 !important;
                right: 0 !important;
                width: 100% !important;
                max-width: 100vw !important;
                box-sizing: border-box !important;
                padding-left: 12px !important;
                padding-right: 12px !important;
            }

            /* The question card itself */
            #root [class*="flex"][class*="flex-col"] > [class*="rounded"],
            #root [class*="flex"][class*="gap"] > [class*="rounded"] {
                max-width: calc(100vw - 24px) !important;
                overflow-wrap: break-word !important;
                word-break: break-word !important;
            }

            /* All text nodes: force wrapping */
            #root p, #root span, #root div, #root li, #root a {
                overflow-wrap: break-word !important;
                word-break: break-word !important;
                max-width: 100% !important;
            }

            /* Links inside question text */
            #root a {
                word-break: break-all !important;
            }

            /* Inline flex items that create horizontal overflow */
            #root [class*="flex-row"],
            #root [class*="flex"][class*="items-center"] {
                flex-wrap: wrap !important;
                max-width: 100% !important;
            }

            /* Chat/message scroll container */
            #root [class*="overflow-y-auto"],
            #root [class*="overflow-y-scroll"] {
                overflow-x: hidden !important;
                max-width: 100vw !important;
            }
        }
    `;

    // Inject styles
    const styleEl = document.createElement('style');
    styleEl.innerHTML = styles;
    document.head.appendChild(styleEl);

    // Create the Remote Control Bar
    function createBar() {
        if (document.getElementById('arc-bar')) return;

        const bar = document.createElement('div');
        bar.id = 'arc-bar';

        bar.innerHTML = `
            <div class="arc-left">
                <div class="arc-logo">
                    <img src="data:image/png;base64," alt="Antigravity" class="arc-logo-img" /> <span class="arc-logo-text">Antigravity Remote</span> <span class="arc-logo-sub">arc</span>
                </div>
                <div class="arc-badge">
                    <div class="arc-dot"></div> <span class="arc-badge-text">Conectado</span>
                </div>
            </div>
            <div class="arc-right">
                <button id="arc-btn-notif" class="arc-btn">
                    ${ICONS.bell} <span class="arc-btn-text">Activar Alertas</span>
                </button>
                <button id="arc-btn-pause" class="arc-btn">
                    ${ICONS.pause} <span class="arc-btn-text">Pausar Sesión</span>
                </button>
                <button id="arc-btn-disconnect" class="arc-btn arc-btn-alert">
                    ${ICONS.power} <span class="arc-btn-text">Desconectar</span>
                </button>
            </div>
        `;

        document.body.appendChild(bar);

        // Toast Container
        const toastContainer = document.createElement('div');
        toastContainer.id = 'arc-toast-container';
        document.body.appendChild(toastContainer);

        // Bind Actions
        const btnNotif = document.getElementById('arc-btn-notif');
        const btnPause = document.getElementById('arc-btn-pause');
        const btnDisconnect = document.getElementById('arc-btn-disconnect');

        let isPaused = false;
        let alertsEnabled = false;

        btnNotif.addEventListener('click', () => {
            if (!alertsEnabled) {
                if ('Notification' in window) {
                    Notification.requestPermission().then(permission => {
                        if (permission === 'granted') {
                            alertsEnabled = true;
                            btnNotif.innerHTML = `${ICONS.bellOff} <span class="arc-btn-text">Desactivar Alertas</span>`;
                            btnNotif.classList.add('arc-btn-active');
                            showToast('¡Alertas activadas! Se te notificará cuando terminen las tareas en segundo plano.');
                        } else {
                            showToast('Permiso de notificaciones denegado.');
                        }
                    });
                } else {
                    showToast('Las notificaciones no son compatibles con este navegador.');
                }
            } else {
                alertsEnabled = false;
                btnNotif.innerHTML = `${ICONS.bell} <span class="arc-btn-text">Activar Alertas</span>`;
                btnNotif.classList.remove('arc-btn-active');
                showToast('Alertas desactivadas.');
            }
        });

        btnPause.addEventListener('click', () => {
            isPaused = !isPaused;
            if (isPaused) {
                btnPause.innerHTML = `${ICONS.play} <span class="arc-btn-text">Reanudar Sesión</span>`;
                btnPause.classList.add('arc-btn-active');
                showToast('Control pausado. Antigravity quedará en espera.');
                sendEvent('pause', { value: true });
            } else {
                btnPause.innerHTML = `${ICONS.pause} <span class="arc-btn-text">Pausar Sesión</span>`;
                btnPause.classList.remove('arc-btn-active');
                showToast('Control remoto reanudado.');
                sendEvent('pause', { value: false });
            }
        });

        btnDisconnect.addEventListener('click', () => {
            if (confirm('¿Estás seguro de que deseas finalizar esta sesión de control remoto?')) {
                showToast('Desconectando el control remoto...');
                sendEvent('disconnect', {});
                setTimeout(() => {
                    window.location.reload();
                }, 1000);
            }
        });

        // Setup WebSocket for dashboard messaging/push triggers
        setupDashboardSocket();
    }

    let ws;
    function setupDashboardSocket() {
        const protocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
        const wsUrl = `${protocol}//${window.location.host}/arc-control-ws`;
        
        ws = new WebSocket(wsUrl);

        ws.onopen = () => {
            console.log('[ARC] WebSocket control channel established.');
        };

        ws.onmessage = (event) => {
            try {
                const data = JSON.parse(event.data);
                if (data.type === 'notification') {
                    triggerPush(data.title, data.body);
                } else if (data.type === 'toast') {
                    showToast(data.message);
                }
            } catch (err) {
                console.error('[ARC] Error parsing websocket message:', err);
            }
        };

        ws.onclose = () => {
            console.warn('[ARC] WebSocket channel disconnected. Retrying in 3s...');
            setTimeout(setupDashboardSocket, 3000);
        };
    }

    function sendEvent(type, payload) {
        if (ws && ws.readyState === WebSocket.OPEN) {
            ws.send(JSON.stringify({ type, payload }));
        }
    }

    function showToast(message) {
        const container = document.getElementById('arc-toast-container');
        if (!container) return;

        const toast = document.createElement('div');
        toast.className = 'arc-toast';
        toast.innerHTML = `${ICONS.info} <div>${message}</div>`;

        container.appendChild(toast);

        setTimeout(() => {
            toast.style.animation = 'none';
            toast.offsetHeight; // trigger reflow
            toast.style.transition = 'opacity 0.5s ease, transform 0.5s ease';
            toast.style.opacity = '0';
            toast.style.transform = 'translateY(-20px)';
            setTimeout(() => {
                toast.remove();
            }, 500);
        }, 4000);
    }

    function triggerPush(title, body) {
        showToast(`Actualización de tarea: ${title} - ${body}`);
        if (Notification.permission === 'granted') {
            new Notification(title, {
                body,
                icon: 'data:image/svg+xml,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 100 100" fill="none" stroke="%2386868b" stroke-width="8" stroke-linecap="round" stroke-linejoin="round"><path d="M50 15 L85 75 L15 75 Z"/></svg>'
            });
        }
    }

    function hideOriginalMenuBar() {
        const keywords = [
            'antigravity', 'file', 'edit', 'view', 'window', 'help',
            'archivo', 'editar', 'ver', 'ventana', 'ayuda'
        ];
        
        const candidates = Array.from(document.querySelectorAll('*')).filter(el => {
            for (let child of el.childNodes) {
                if (child.nodeType === Node.TEXT_NODE) {
                    const text = child.textContent.toLowerCase().trim();
                    if (keywords.includes(text)) {
                        return true;
                    }
                }
            }
            return false;
        });

        if (candidates.length >= 2) {
            let parent = candidates[0].parentElement;
            while (parent && parent !== document.body) {
                const containsAll = candidates.every(c => parent.contains(c));
                if (containsAll) {
                    const rect = parent.getBoundingClientRect();
                    if (rect.height < 120 && rect.top < 250) {
                        console.log('[ARC] Menu bar parent container located and hidden:', parent);
                        parent.style.setProperty('display', 'none', 'important');
                        break;
                    }
                }
                parent = parent.parentElement;
            }
        }

        // Pull up top absolute/fixed/spaced panels that were shifted by the original top menu bar
        const layoutElements = document.querySelectorAll('#root div, #root section, #root header, #root nav, #root main');
        for (let el of layoutElements) {
            const style = window.getComputedStyle(el);
            
            // 1. Check absolute/fixed positioning top
            if (style.position === 'absolute' || style.position === 'fixed') {
                const topVal = parseFloat(style.top);
                if (!isNaN(topVal) && topVal > 25 && topVal < 80) {
                    el.style.setProperty('top', '0px', 'important');
                }
            }
            
            // 2. Check margin-top
            const mtVal = parseFloat(style.marginTop);
            if (!isNaN(mtVal) && mtVal > 25 && mtVal < 80) {
                el.style.setProperty('margin-top', '0px', 'important');
            }
            
            // 3. Check padding-top
            const ptVal = parseFloat(style.paddingTop);
            if (!isNaN(ptVal) && ptVal > 25 && ptVal < 80) {
                el.style.setProperty('padding-top', '0px', 'important');
            }
        }

        // Double-safety: Find and remove any leftover text nodes containing the birthday gift emoji
        const walker = document.createTreeWalker(document.body, NodeFilter.SHOW_TEXT, null, false);
        let node;
        const nodesToRemove = [];
        while (node = walker.nextNode()) {
            if (node.textContent.includes('🎁')) {
                nodesToRemove.push(node);
            }
        }
        for (let n of nodesToRemove) {
            console.log('[ARC] Dangling favicon text node wiped:', n.textContent);
            n.textContent = '';
        }
    }

    function startMenuBarHider() {
        // Initial search
        hideOriginalMenuBar();

        // Periodically check as React loads
        const interval = setInterval(hideOriginalMenuBar, 300);
        setTimeout(() => clearInterval(interval), 15000);

        // Reactive check via MutationObserver
        const observer = new MutationObserver(hideOriginalMenuBar);
        observer.observe(document.body, { childList: true, subtree: true });
        setTimeout(() => observer.disconnect(), 20000);
    }

    // Wait until DOM is fully constructed before attaching our premium dashboard
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', () => {
            createBar();
            startMenuBarHider();
        });
    } else {
        createBar();
        startMenuBarHider();
    }
})();
